const now = new Date();
const windowEnd = new Date(Math.floor(now.getTime() / 300000) * 300000);  // round down to nearest 5min
const windowStart = new Date(windowEnd.getTime() - 300000);
return { json: { window_start: windowStart.toISOString(), window_end: windowEnd.toISOString(), started_after: windowStart.toISOString() } };

// Build sentinel_workflow_health rows from n8n API responses.
// Pulls window from Compute Window; executions from Fetch n8n Executions;
// active workflow list from Fetch Active Workflows (so silent workflows still get a row).
const window = $('Compute Window').first().json;
const execsResp = $('Fetch n8n Executions').first().json || {};
const wfsResp   = $('Fetch Active Workflows').first().json || {};
const execs = Array.isArray(execsResp.data) ? execsResp.data : (Array.isArray(execsResp) ? execsResp : []);
const wfs   = Array.isArray(wfsResp.data)   ? wfsResp.data   : (Array.isArray(wfsResp)   ? wfsResp   : []);

// Filter executions to the window.
const winStart = new Date(window.window_start).getTime();
const winEnd   = new Date(window.window_end).getTime();
const inWindow = execs.filter(function (e) {
  const t = new Date(e.startedAt || e.createdAt || 0).getTime();
  return t >= winStart && t < winEnd;
});

// Build a name lookup from the workflows list (silent workflows otherwise have no name in exec rows).
const nameById = {};
wfs.forEach(function (w) { nameById[String(w.id)] = w.name; });

// Aggregate by workflow_id.
const agg = {};
inWindow.forEach(function (e) {
  const wid = String(e.workflowId || e.workflow_id || '');
  if (!wid) return;
  if (!agg[wid]) agg[wid] = { workflow_id: wid, workflow_name: nameById[wid] || e.workflowData && e.workflowData.name || null, executions: 0, success: 0, error: 0, waiting: 0, durations: [], last_exec_at: null };
  agg[wid].executions += 1;
  const status = String(e.status || e.finished === false ? 'waiting' : (e.stoppedAt ? 'success' : 'unknown')).toLowerCase();
  // n8n statuses: success | error | waiting | running | canceled | crashed
  if (status === 'error' || status === 'crashed' || status === 'failed') agg[wid].error += 1;
  else if (status === 'waiting' || status === 'running') agg[wid].waiting += 1;
  else if (status === 'success') agg[wid].success += 1;
  else { agg[wid].success += (e.stoppedAt && !e.error ? 1 : 0); }
  if (e.startedAt && e.stoppedAt) {
    const dur = new Date(e.stoppedAt).getTime() - new Date(e.startedAt).getTime();
    if (dur >= 0 && dur < 24*3600*1000) agg[wid].durations.push(dur);
  }
  const ts = e.startedAt || e.stoppedAt || null;
  if (ts && (!agg[wid].last_exec_at || ts > agg[wid].last_exec_at)) agg[wid].last_exec_at = ts;
});

// Ensure every active workflow gets a row, even if it had zero executions (silent detection).
wfs.forEach(function (w) {
  const wid = String(w.id);
  if (!agg[wid]) agg[wid] = { workflow_id: wid, workflow_name: w.name, executions: 0, success: 0, error: 0, waiting: 0, durations: [], last_exec_at: null };
});

// p95 helper.
function p95(arr) {
  if (!arr.length) return 0;
  const s = arr.slice().sort(function (a, b) { return a - b; });
  const idx = Math.min(s.length - 1, Math.floor(s.length * 0.95));
  return s[idx];
}
function avg(arr) {
  if (!arr.length) return 0;
  return Math.round(arr.reduce(function (a, b) { return a + b; }, 0) / arr.length);
}

const rows = Object.keys(agg).map(function (wid) {
  const a = agg[wid];
  // Status heuristic — analyzer applies SLO thresholds for final classification.
  let status = 'healthy';
  if (a.executions === 0) status = 'silent';
  else if (a.executions > 0 && (a.error * 100 / a.executions) >= 25) status = 'critical';
  else if (a.executions > 0 && (a.error * 100 / a.executions) >= 10) status = 'degraded';
  return {
    workflow_id: a.workflow_id,
    workflow_name: a.workflow_name,
    window_start: window.window_start,
    window_end:   window.window_end,
    execution_count: a.executions,
    success_count: a.success,
    error_count:   a.error,
    waiting_count: a.waiting,
    avg_duration_ms: avg(a.durations),
    p95_duration_ms: p95(a.durations),
    last_execution_at: a.last_exec_at,
    status: status
  };
});

return rows.map(function (r) { return { json: r }; });

const rows = $('Aggregate').all().map(function (i) { return i.json; });
const counts = { healthy: 0, degraded: 0, critical: 0, silent: 0 };
rows.forEach(function (r) { counts[r.status] = (counts[r.status] || 0) + 1; });
return { json: { ok: true, workflows_evaluated: rows.length, counts: counts, window_start: rows[0] ? rows[0].window_start : null, window_end: rows[0] ? rows[0].window_end : null } };
